// ============================================================================
// PARSE LUNA RESPONSE & EXTRACT COMMANDS
// ============================================================================

const lunaOutput = $input.first().json;
let responseText = '';

if (typeof lunaOutput.output === 'string') {
  responseText = lunaOutput.output;
} else if (lunaOutput.output && typeof lunaOutput.output === 'object') {
  responseText = JSON.stringify(lunaOutput.output);
} else {
  responseText = lunaOutput.text || '';
}

const commandPattern = /COMMAND:\s*([A-Z_]+)[\s\S]*?REASON:\s*([^\n]+)[\s\S]*?PAYLOAD:\s*(\{[\s\S]*?\})/g;
const commands = [];

let match;
while ((match = commandPattern.exec(responseText)) !== null) {
  const [_, command, reason, payloadStr] = match;
  try {
    const payload = JSON.parse(payloadStr);
    commands.push({ command, reason, payload });
  } catch (e) {
    console.error('Failed to parse command payload:', e);
  }
}

const prepareContext = $('Prepare Luna Context').item.json;

return [{
  json: {
    agent_response: {
      message: responseText.split('COMMAND:')[0].trim(),
      agent_used: 'luna',
      commands,
      raw_response: responseText
    },
    context: prepareContext.full_context
  }
}];

// ============================================================================
// EXECUTE WRITE-BACK COMMANDS TO SUPABASE (REAL)
// ============================================================================

const { commands } = $input.item.json.agent_response;
const context = $input.item.json.context;
const projectId = context.project.id;
const taskId = context.task?.id;

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;

async function supabaseRequest(endpoint, options = {}) {
  const response = await fetch(`${SUPABASE_URL}/rest/v1/${endpoint}`, {
    ...options,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation',
      ...options.headers
    }
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Supabase error (${response.status}): ${errorText}`);
  }

  return await response.json();
}

const executionResults = [];

for (const cmd of commands) {
  try {
    switch (cmd.command) {
      case 'MEMORY_WRITE':
        const memoryData = {
          project_id: projectId,
          task_id: taskId,
          agent_id: 'luna',
          action: cmd.payload.action || 'STRATEGY_VALIDATED',
          summary: cmd.payload.summary,
          key_findings: cmd.payload.key_findings || [],
          deliverables: cmd.payload.deliverables || [],
          recommendations: cmd.payload.recommendations || [],
          context_snapshot: cmd.payload.context_snapshot || {},
          session_id: context.session_id
        };

        const memoryResult = await supabaseRequest('project_memory', {
          method: 'POST',
          body: JSON.stringify(memoryData)
        });

        executionResults.push({
          command: 'MEMORY_WRITE',
          success: true,
          result: memoryResult
        });
        break;

      case 'UPDATE_TASK_STATUS':
        if (!taskId) {
          executionResults.push({
            command: 'UPDATE_TASK_STATUS',
            success: false,
            error: 'No task_id available'
          });
          break;
        }

        const taskUpdate = {
          status: cmd.payload.status,
          deliverable_url: cmd.payload.deliverable_url || null,
          deliverable_type: cmd.payload.deliverable_type || null
        };

        if (cmd.payload.status === 'done') {
          taskUpdate.completed_at = new Date().toISOString();
        } else if (cmd.payload.status === 'in_progress') {
          taskUpdate.started_at = new Date().toISOString();
        }

        const taskResult = await supabaseRequest(`tasks?id=eq.${taskId}`, {
          method: 'PATCH',
          body: JSON.stringify(taskUpdate)
        });

        executionResults.push({
          command: 'UPDATE_TASK_STATUS',
          success: true,
          result: taskResult
        });
        break;

      case 'UI_COMPONENT':
        executionResults.push({
          command: 'UI_COMPONENT',
          success: true,
          ui_component: cmd.payload
        });
        break;

      default:
        executionResults.push({
          command: cmd.command,
          success: false,
          error: `Unknown command: ${cmd.command}`
        });
    }
  } catch (error) {
    executionResults.push({
      command: cmd.command,
      success: false,
      error: error.message
    });
  }
}

const uiComponents = executionResults
  .filter(r => r.ui_component)
  .map(r => r.ui_component);

return [{
  json: {
    success: true,
    commands_executed: executionResults.length,
    execution_results: executionResults,
    agent_response: $input.item.json.agent_response,
    ui_components: uiComponents,
    project_id: projectId,
    task_id: taskId
  }
}];
